"use client";

import { useState } from "react";
import { Utensils, Smartphone, Sofa, ShowerHead, Shirt, Tv, Cookie } from "lucide-react";
import Navbar from "../navbar";
import Footer from "../footer";
import CartSidebarWrapper from "../shopcart/CartSidebarWrapper";

export default function SearchPage() {
    const [isCartOpen, setIsCartOpen] = useState(false);

    // cartItems เหมือน HomePage
    const [cartItems, setCartItems] = useState([
        { id: 1, name: "Be Nice Shower Cream, Perfect Elastic Formula, 450 ml.", price: 109, qty: 1, stock: 5, image: "/images/products/showercream.png", warning: false },
        { id: 2, name: "Protex Lavender Ice Freeze Soap Bar 60 g.", price: 19, qty: 3, stock: 3, image: "/images/products/protex.png", warning: false },
        { id: 3, name: "KFC BamBam BOX Menu TheBox special", price: 159, qty: 1, stock: 20, image: "/images/products/kfc.png", warning: false },
    ]);

    // ฟังก์ชันจัดการสินค้าใน cart
    const increaseQty = (id) => {
        setCartItems(prev =>
            prev.map(item => {
                if (item.id === id) {
                    if (item.qty + 1 > item.stock) {
                        return { ...item, warning: true };
                    }
                    return { ...item, qty: item.qty + 1, warning: false };
                }
                return item;
            })
        );
    };

    const decreaseQty = (id) => {
        setCartItems(prev =>
            prev.map(item => {
                if (item.id === id) {
                    const newQty = Math.max(item.qty - 1, 1);
                    return { ...item, qty: newQty, warning: false };
                }
                return item;
            })
        );
    };

    const removeItem = (id) => {
        setCartItems(prev => prev.filter(item => item.id !== id));
    };

    // หมวดหมู่
    const categories = [
        { name: "Snacks", icon: <Cookie size={18} /> },
        { name: "Food & Drink", icon: <Utensils size={18} /> },
        { name: "Smartphone", icon: <Smartphone size={18} /> },
        { name: "Furniture", icon: <Sofa size={18} /> },
        { name: "Shower", icon: <ShowerHead size={18} /> },
        { name: "Clothing", icon: <Shirt size={18} /> },
        { name: "Electronics", icon: <Tv size={18} /> },
    ];

    // สินค้า mock data
    const products = Array(8).fill({
        id: 3,
        name: "KFC BamBam BOX Menu TheBox special",
        desc: "Menu TheBox special",
        price: 159,
        image: "/images/products/kfc.png",
        category: "Food & Drink"
    });

    return (
        <div className="font-sans bg-white relative">
            {/* Blur wrapper */}
            <div className={`${isCartOpen ? "blur-sm pointer-events-none" : ""} transition-all duration-300`}>
                {/* Navbar */}
                <Navbar cartItems={cartItems} onCartOpen={() => setIsCartOpen(true)} />

                <main className="max-w-7xl mx-auto px-6 py-6 flex gap-8">
                    {/* Sidebar filter */}
                    <aside className="w-1/4">
                        <h3 className="text-gray-600 text-sm mb-2">Categories</h3>
                        <ul className="mb-6">
                            {categories.map((c) => (
                                <li
                                    key={c.name}
                                    className={`px-3 py-2 rounded-md mb-1 cursor-pointer ${
                                        c.name === "Food & Drink"
                                            ? "bg-green-500 text-white"
                                            : "hover:bg-gray-100"
                                    }`}
                                >
                                    <div className="flex items-center gap-2">
                                        {c.icon}
                                        <span>{c.name}</span>
                                    </div>
                                </li>
                            ))}
                        </ul>

                        <h3 className="text-gray-600 text-sm mb-2">Price</h3>
                        <div className="flex flex-col gap-2 text-sm">
                            <label><input type="checkbox" className="mr-2" /> $1–$249</label>
                            <label><input type="checkbox" className="mr-2" /> $250–$1,049</label>
                            <label><input type="checkbox" className="mr-2" /> $1,050–$2,999</label>
                            <label><input type="checkbox" className="mr-2" /> $3,000–$5,000</label>
                            <label><input type="checkbox" className="mr-2" /> $5,000–$10,000</label>
                        </div>
                    </aside>

                    {/* Products section */}
                    <section className="flex-1">
                        <h2 className="text-2xl font-semibold mb-6">Food & Drink</h2>
                        <div className="grid grid-cols-3 lg:grid-cols-4 gap-6">
                            {products.map((p, idx) => (
                                <div key={idx} className="border rounded-lg overflow-hidden hover:shadow-md transition">
                                    <img src={p.image} alt={p.name} className="w-full h-40 object-cover" />
                                    <div className="p-4">
                                        <h3 className="font-medium text-sm">{p.name}</h3>
                                        <p className="text-xs text-gray-500">{p.desc}</p>
                                        <p className="mt-2 font-semibold">${p.price.toFixed(2)}</p>
                                        <button
                                            className="mt-2 w-full bg-green-600 text-white py-1 rounded text-sm"
                                        >
                                            + Add
                                        </button>
                                    </div>
                                </div>
                            ))}
                        </div>

                        {/* Pagination */}
                        <div className="flex justify-center mt-8 gap-2">
                            <button className="px-3 py-1 border rounded">&lt;</button>
                            <button className="px-3 py-1 border rounded bg-green-600 text-white">1</button>
                            <button className="px-3 py-1 border rounded">2</button>
                            <button className="px-3 py-1 border rounded">...</button>
                            <button className="px-3 py-1 border rounded">12</button>
                            <button className="px-3 py-1 border rounded">&gt;</button>
                        </div>
                    </section>
                </main>

                {/* Footer */}
                <Footer />
            </div>

            {/* Cart Sidebar */}
            <CartSidebarWrapper
                isCartOpen={isCartOpen}
                onClose={() => setIsCartOpen(false)}
                cartItems={cartItems}
                increaseQty={increaseQty}
                decreaseQty={decreaseQty}
                removeItem={removeItem}
            />
        </div>
    );
}
